const files = $input.first().json.files || [];
if (files.length === 0) return [{ json: { skip: true } }];
return files.map(function(f) {
  return { json: { fileName: f.fileName, filePath: f.filePath } };
});

// استخراج جميع الروابط من الملف ومعالجتها بالتوالي
const fileData = $input.first().json;
const prevData = $('🔀 تقسيم الملفات').first().json;
const content = fileData.content || '';
const fileName = fileData.fileName || prevData.fileName;
const filePath = fileData.filePath || prevData.filePath;

// استخراج جميع الأسطر وتنظيفها
const lines = content.split('\n').map(function(l) { return l.trim(); }).filter(function(l) { return l.length > 0; });

// استخراج الروابط فقط
const urls = lines.filter(function(l) { return l.startsWith('http://') || l.startsWith('https://'); });

if (urls.length === 0) return [{ json: { skip: true, fileName: fileName, reason: 'لا توجد روابط في الملف' } }];

// إنتاج عنصر لكل رابط مع رقم تسلسلي
const baseName = fileName.replace(/\.(txt|url|md)$/i, '').replace(/[_\-]/g, ' ').trim();

return urls.map(function(url, i) {
  const title = urls.length > 1 ? baseName + ' (' + (i + 1) + ' من ' + urls.length + ')' : baseName;
  return { json: {
    url: url,
    title: title,
    fileName: fileName,
    filePath: filePath,
    urlIndex: i + 1,
    urlTotal: urls.length
  }};
});

const d = $input.first().json;
if (d.skip || !d.url) return [{ json: { skip: true } }];
const url = d.url;
let type = 'webpage';
if (url.indexOf('youtube.com') !== -1 || url.indexOf('youtu.be') !== -1) type = 'youtube';
else if (url.indexOf('twitter.com') !== -1 || url.indexOf('x.com') !== -1) type = 'twitter';
else if (url.indexOf('linkedin.com') !== -1) type = 'linkedin';
else if (url.indexOf('facebook.com') !== -1) type = 'facebook';
else if (url.indexOf('instagram.com') !== -1) type = 'instagram';
else if (url.indexOf('tiktok.com') !== -1) type = 'tiktok';
else if (url.indexOf('reddit.com') !== -1) type = 'reddit';
else if (/\.(mp3|wav|ogg|aac)$/i.test(url)) type = 'audio';
else if (/\.(mp4|avi|mov|mkv)$/i.test(url)) type = 'video';
else if (/\.pdf$/i.test(url)) type = 'pdf';
const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const safe = (d.title || type).replace(/[^\u0600-\u06FFa-zA-Z0-9 ]/g, '').trim().slice(0, 50);
return [{ json: Object.assign({}, d, { type: type, outputFilename: ts + '_' + safe + '.md', timestamp: ts }) }];

const typeData = $('🔍 تحديد نوع الرابط').first().json;
const jinaData = $input.first().json;
let rawContent = jinaData.body || jinaData.data || '';

// تنظيف المحتوى حسب نوع الرابط
let cleanContent = rawContent;

if (typeData.type === 'tiktok') {
  // استخراج وصف الفيديو والهاشتاقات فقط من TikTok
  const lines = rawContent.split('\n');
  const relevantLines = [];
  let foundDescription = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    // تخطي الأسطر الفارغة في البداية وعناصر التنقل
    if (!foundDescription && (line === '' || line === 'Log in' || line === 'Search' || 
        line === 'For You' || line === 'Shop' || line === 'Explore' || 
        line === 'Following' || line === 'LIVE' || line === 'Upload' || 
        line === 'Profile' || line === 'More' || line.startsWith('©'))) {
      continue;
    }
    // ابدأ التقاط المحتوى من أول سطر يحتوي على نص حقيقي
    if (!foundDescription && line.length > 10 && !line.startsWith('[![') && !line.startsWith('[**')) {
      foundDescription = true;
    }
    if (foundDescription) {
      // توقف عند قسم التعليقات أو الفيديوهات المقترحة
      if (line === 'Comments' || line === 'You may like' || line === 'Log in' ||
          line.startsWith('Introducing keyboard') || line.startsWith('Go to previous')) {
        break;
      }
      // تخطي روابط الصور والفيديوهات المقترحة
      if (line.startsWith('[![') || (line.startsWith('[') && line.includes('ago'))) {
        continue;
      }
      if (line.length > 0) {
        relevantLines.push(line);
      }
    }
  }
  cleanContent = relevantLines.join('\n').trim();
  // إذا كان المحتوى قصيراً جداً، استخدم المحتوى الأصلي
  if (cleanContent.length < 50) {
    cleanContent = rawContent.slice(0, 2000);
  }
} else if (typeData.type === 'youtube') {
  // لـ YouTube: استخرج الوصف والعنوان فقط
  const descMatch = rawContent.match(/Description[:\s]+([\s\S]{0,1500})/);
  cleanContent = descMatch ? descMatch[1].trim() : rawContent.slice(0, 3000);
} else {
  // للمواقع العادية: اقتطع بذكاء
  cleanContent = rawContent.slice(0, 4000);
}

const prompt = 'أنت مساعد متخصص في تلخيص المحتوى الرقمي. النوع: ' + typeData.type + '\nالمصدر: ' + typeData.url + '\n\nالمهمة:\n1. اكتب ملخصاً موجزاً (3-5 أسطر)\n2. استخرج 5 نقاط رئيسية\n3. حدد 5 كلمات مفتاحية\n\nالمحتوى:\n' + cleanContent.slice(0, 3000) + '\n\nأجب بالعربية بصيغة Markdown مع عناوين واضحة.';

return [{ json: { prompt: prompt, jinaContent: cleanContent, rawContent: rawContent } }];

const typeData = $('🔍 تحديد نوع الرابط').first().json;
const prepData = $('🧠 تجهيز البرومبت').first().json;
const aiData = $input.first().json;
const content = prepData.jinaContent || '';
const summary = aiData.response || '';
const wordCount = content.split(/\s+/).filter(function(w) { return w.length > 0; }).length;
const dateStr = new Date().toLocaleDateString('ar-SA');

// بناء outputFilename هنا مباشرة لضمان وجوده
const ts = typeData.timestamp || new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const safe = (typeData.title || typeData.type || 'url').replace(/[^؀-ۿa-zA-Z0-9 ]/g, '').trim().slice(0, 50).replace(/\s+/g, '_');
const outputFilename = ts + '_' + safe + '.md';

// معلومات الرابط المتعدد
const urlInfo = typeData.urlTotal > 1 ? '
**الرابط:** ' + typeData.urlIndex + ' من ' + typeData.urlTotal : '';

const md = '---
title: "' + (typeData.title || typeData.url) + '"
url: ' + typeData.url + '
type: ' + typeData.type + '
date: ' + ts + '
words: ' + wordCount + '
source_file: ' + typeData.fileName + '
---

# ' + (typeData.title || typeData.url) + '

**المصدر:** ' + typeData.url + '  
**النوع:** ' + typeData.type + '  
**التاريخ:** ' + dateStr + urlInfo + '  
**الملف الأصلي:** ' + typeData.fileName + '

---

## الملخص الذكي

' + summary + '

---

## المحتوى المُنظَّف

' + content + '
';
return [{ json: Object.assign({}, typeData, { markdown: md, wordCount: wordCount, outputFilename: outputFilename, fileName: typeData.fileName, filePath: typeData.filePath, urlIndex: typeData.urlIndex, urlTotal: typeData.urlTotal }) }];

// نقل الملف الأصلي فقط بعد معالجة آخر رابط فيه
const markdownData = $('📝 بناء Markdown').first().json;
const isLastUrl = markdownData.urlIndex === markdownData.urlTotal;

if (!isLastUrl) {
  // ليس آخر رابط — لا ننقل الملف بعد
  return [{ json: Object.assign({}, markdownData, { moved: false, reason: 'انتظار معالجة باقي الروابط (' + markdownData.urlIndex + '/' + markdownData.urlTotal + ')' }) }];
}

// آخر رابط — نمرر البيانات لعقدة النقل
return [{ json: Object.assign({}, markdownData, { moved: true, readyToMove: true }) }];

const data = $('📌 آخر رابط؟').first().json;
return [{ json: {
  success: true,
  sourceFile: data.fileName,
  outputFile: data.outputFilename,
  url: data.url,
  type: data.type,
  words: data.wordCount,
  urlIndex: data.urlIndex,
  urlTotal: data.urlTotal,
  timestamp: new Date().toISOString()
} }];
